window.HK_LC7 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["Products are stacked on shelves.", "A keyboard is being moved.", "A man is tightening a tie.", "The people are exchanging clipboards."], "optko": ["제품들이 선반에 쌓여 있다.", "키보드가 옮겨지고 있다.", "한 남자가 넥타이를 조이고 있다.", "사람들이 클립보드를 교환하고 있다."], "ans": 0, "audio": "Test07_01.mp3", "img": "hk_t7_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["She is looking out of a window.", "She is fastening a seat belt.", "She is reading a magazine.", "She is lowering a tray table."], "optko": ["그녀는 창밖을 보고 있다.", "그녀는 안전벨트를 매고 있다.", "그녀는 잡지를 읽고 있다.", "그녀는 간이 탁자를 낮추고 있다."], "ans": 2, "audio": "Test07_02.mp3", "img": "hk_t7_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["A man is plugging in a power tool.", "A man is working on some equipment.", "A man is giving a demonstration to others.", "A man is comparing different screwdrivers."], "optko": ["한 남자가 전동 공구에 전원을 연결하고 있다.", "한 남자가 기기에 작업을 하고 있다.", "한 남자가 다른 사람들에게 시연을 하고 있다.", "한 남자가 여러 스크루드라이버들을 비교하고 있다."], "ans": 1, "audio": "Test07_03.mp3", "img": "hk_t7_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["Baked goods are being purchased.", "Food has been laid out on a counter.", "Some bread has been put into an oven.", "Light fixtures are being hung up."], "optko": ["제과들이 구매되고 있다.", "음식이 판매대에 놓여 있다.", "몇몇 빵이 오븐에 넣어졌다.", "조명 기구가 매달아지고 있다."], "ans": 1, "audio": "Test07_04.mp3", "img": "hk_t7_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["Some people are moving a lamp.", "Some people are chatting by a table.", "Some people are closing a window.", "Some people are clearing off some desks."], "optko": ["몇몇 사람들이 전등을 옮기고 있다.", "몇몇 사람들이 탁자 옆에서 이야기하고 있다.", "몇몇 사람들이 창문을 닫고 있다.", "몇몇 사람들이 책상을 치우고 있다."], "ans": 1, "audio": "Test07_05.mp3", "img": "hk_t7_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["Some curtains are being replaced.", "A flower arrangement is on a windowsill.", "A rug has been set under the furniture.", "Some cushions are on a sofa."], "optko": ["커튼들이 교체되고 있다.", "꽃꽂이 장식이 창문턱에 있다.", "깔개가 가구 밑에 놓여 있다.", "쿠션들이 소파 위에 있다."], "ans": 3, "audio": "Test07_06.mp3", "img": "hk_t7_q6.jpg"}, {"n": 7, "part": 2, "q": "Which musician will be performing at the award ceremony?", "qko": "어느 음악가가 시상식에서 공연하게 될까요?", "opts": ["The same guitar player as last year.", "A prize valued at $500.", "Ms. Thomas discovered the defect."], "optko": ["작년과 동일한 기타 연주자요.", "500달러 가치의 상이에요.", "Ms. Thomas가 결함을 발견했어요."], "ans": 0, "audio": "Test07_07.mp3"}, {"n": 8, "part": 2, "q": "Where can we hang our poster for the event?", "qko": "행사를 위한 우리의 포스터를 어디에 걸 수 있나요?", "opts": ["The event organizer.", "OK. I'll print more of them.", "On the bulletin board."], "optko": ["행사 주최자요.", "알겠습니다. 그것들을 더 인쇄할게요.", "게시판이에요."], "ans": 2, "audio": "Test07_08.mp3"}, {"n": 9, "part": 2, "q": "Would you like to go to a new Chinese restaurant with us?", "qko": "저희와 함께 새로 생긴 중식당에 가실래요?", "opts": ["No, thanks. I've already eaten.", "A plant opening in China.", "Yes, I did."], "optko": ["아니요, 괜찮아요. 저는 이미 먹었어요.", "중국에 문을 여는 공장이요.", "네, 제가 했어요."], "ans": 0, "audio": "Test07_09.mp3"}, {"n": 10, "part": 2, "q": "When am I supposed to shut down the store?", "qko": "제가 언제 가게의 문을 닫아야 하나요?", "opts": ["At 8 P.M.", "Just down the street.", "We bought this candle there."], "optko": ["오후 8시예요.", "그 길 바로 아래요.", "우리는 이 양초를 그곳에서 샀어요."], "ans": 0, "audio": "Test07_10.mp3"}, {"n": 11, "part": 2, "q": "How many desktop computers were ordered for the library?", "qko": "도서관에 몇 대의 데스크톱 컴퓨터가 주문되었나요?", "opts": ["Up to five books can be checked out.", "Set up on the desk.", "Mr. Collins can provide that information."], "optko": ["다섯 권까지 책을 빌릴 수 있어요.", "책상 위에 설치해 주세요.", "Mr. Collins가 그 정보를 제공해드릴 수 있어요."], "ans": 2, "audio": "Test07_11.mp3"}, {"n": 12, "part": 2, "q": "This luggage is heavier than I thought it would be.", "qko": "이 짐은 제가 예상했던 것보다 더 무겁네요.", "opts": ["Would you like me to carry it?", "At the baggage claim area.", "We thought it was a nice hotel."], "optko": ["제가 그걸 들어드릴까요?", "수하물 찾는 곳에서요.", "우리는 그곳이 좋은 호텔이라고 생각했어요."], "ans": 0, "audio": "Test07_12.mp3"}, {"n": 13, "part": 2, "q": "Can my phone plan be upgraded to include unlimited texting?", "qko": "제 휴대 전화 요금제가 무제한 문자 메시지를 포함하도록 업그레이드될 수 있나요?", "opts": ["Your own work number.", "I can take care of that.", "No, seat upgrades are excluded."], "optko": ["당신의 회사 번호요.", "제가 그것을 처리해드릴 수 있어요.", "아니요, 좌석 업그레이드는 제외됩니다."], "ans": 1, "audio": "Test07_13.mp3"}, {"n": 14, "part": 2, "q": "I thought we could have shortened the presentation.", "qko": "우리가 발표를 단축할 수 있었을 거라고 생각했어요.", "opts": ["Actually, it's a pretty long hallway.", "It was a present from a friend.", "Yes, I completely agree."], "optko": ["사실, 그것은 꽤 긴 복도예요.", "이것은 친구에게 받은 선물이었어요.", "네, 저는 완전히 동의해요."], "ans": 2, "audio": "Test07_14.mp3"}, {"n": 15, "part": 2, "q": "Why wasn't the photocopier we ordered installed this afternoon?", "qko": "왜 우리가 주문한 복사기가 오늘 오후에 설치되지 않았나요?", "opts": ["It was.", "From an electronics store.", "The installation instructions."], "optko": ["설치되었어요.", "전자 제품 매장으로부터요.", "설치 설명서요."], "ans": 0, "audio": "Test07_15.mp3"}, {"n": 16, "part": 2, "q": "Should we organize the workshops for May or June?", "qko": "우리는 워크숍을 5월 또는 6월에 개최해야 하나요?", "opts": ["No, we didn't attend.", "Because the shop was empty.", "I'd prefer to have them earlier."], "optko": ["아니요, 우리는 참석하지 않았어요.", "가게가 비어 있었기 때문이에요.", "저는 더 일찍 하면 좋겠어요."], "ans": 2, "audio": "Test07_16.mp3"}, {"n": 17, "part": 2, "q": "What type of fabric did you order for the scarves?", "qko": "당신은 스카프를 위해 어떤 종류의 천을 주문했나요?", "opts": ["At a trade fair.", "Because it's affordable.", "I want to get more samples first."], "optko": ["무역 박람회에서요.", "그것이 저렴하기 때문이에요.", "저는 우선 더 많은 샘플을 얻고 싶어요."], "ans": 2, "audio": "Test07_17.mp3"}, {"n": 18, "part": 2, "q": "This is the correct patient form, isn't it?", "qko": "이것이 정확한 환자 진료 양식이죠, 그렇지 않나요?", "opts": ["Form a line over there.", "No, there's a newer version.", "Only the first patient."], "optko": ["저쪽에 한 줄로 정렬하세요.", "아니요, 더 최신 버전이 있어요.", "첫 번째 환자만요."], "ans": 1, "audio": "Test07_18.mp3"}, {"n": 19, "part": 2, "q": "We should e-mail Mr. Murray about the contract changes.", "qko": "우리는 Mr. Murray에게 계약 변경 사항에 대한 이메일을 보내야 해요.", "opts": ["Various legal requirements.", "Yes, he'll want to know.", "I don't have exact change."], "optko": ["다양한 법률 요건이요.", "네, 그는 알고 싶어 할 거예요.", "저는 딱 맞는 거스름돈이 없어요."], "ans": 1, "audio": "Test07_19.mp3"}, {"n": 20, "part": 2, "q": "Where is the conference on biotechnology being hosted?", "qko": "생명 공학에 관한 학회가 어디에서 열리고 있나요?", "opts": ["Both medical products and services.", "A venue in downtown Boston.", "Mindy organized the retirement party."], "optko": ["의료 제품과 서비스 둘 다요.", "보스턴 시내의 한 장소요.", "Mindy가 은퇴 파티를 준비했어요."], "ans": 1, "audio": "Test07_20.mp3"}, {"n": 21, "part": 2, "q": "Why don't you take the highway?", "qko": "고속도로를 이용하는 게 어때요?", "opts": ["I don't believe there are.", "That's the next rest stop.", "One of the lanes is closed until Friday."], "optko": ["있는 것 같지 않아요.", "그것은 다음 휴게소예요.", "도로 중 하나가 금요일까지 폐쇄돼요."], "ans": 2, "audio": "Test07_21.mp3"}, {"n": 22, "part": 2, "q": "Didn't we download the latest software recently?", "qko": "우리가 최근에 최신 소프트웨어를 다운로드하지 않았나요?", "opts": ["It was downloaded just the other day.", "No, this isn't my computer.", "The hardware came with a warranty."], "optko": ["그것은 바로 며칠 전에 다운로드 되었어요.", "아니요, 이것은 제 컴퓨터가 아니에요.", "하드웨어에 품질 보증서가 딸려 있었어요."], "ans": 0, "audio": "Test07_22.mp3"}, {"n": 23, "part": 2, "q": "We're offering a discount on cleaning supplies this month, right?", "qko": "우리는 이번 달에 청소 용품에 대한 할인을 제공해요, 그렇죠?", "opts": ["I'll have to count them.", "That's a good question.", "It was returned on June 4."], "optko": ["저는 그것들을 세어 봐야 할 거예요.", "좋은 질문이네요.", "이것은 6월 4일에 반납되었어요."], "ans": 1, "audio": "Test07_23.mp3"}, {"n": 24, "part": 2, "q": "Have we published more articles this year than last year?", "qko": "우리는 작년보다 올해에 더 많은 기사들을 발표했나요?", "opts": ["I haven't worked here long enough to say.", "The article is much too long.", "I thought you had edited it already."], "optko": ["저는 말할 수 있을 만큼 여기서 오래 일하지 않았어요.", "그 기사는 너무 길어요.", "저는 당신이 그것을 이미 수정했다고 생각했어요."], "ans": 0, "audio": "Test07_24.mp3"}, {"n": 25, "part": 2, "q": "Could I get another filing cabinet for the reception desk?", "qko": "접수처에 둘 문서 보관함을 하나 더 받을 수 있을까요?", "opts": ["At the top of the document.", "We don't have any spare ones right now.", "Files are typically sent through e-mail."], "optko": ["서류 위에요.", "우리는 현재 여분이 없어요.", "서류들은 보통 이메일을 통해 전달돼요."], "ans": 1, "audio": "Test07_25.mp3"}, {"n": 26, "part": 2, "q": "When is the budget proposal due?", "qko": "예산안의 기한이 언제인가요?", "opts": ["I sent out a memo about it.", "Yes, we need to cut costs.", "It's over budget."], "optko": ["제가 그것에 대한 회람을 보냈어요.", "네, 우리는 비용을 줄여야 해요.", "예산 초과예요."], "ans": 0, "audio": "Test07_26.mp3"}, {"n": 27, "part": 2, "q": "Should we pick up the cake or have it delivered?", "qko": "우리가 케이크를 찾아와야 할까요, 아니면 그것을 배달시켜야 할까요?", "opts": ["Whichever is easier.", "Let's get chocolate.", "Usually within 30 minutes."], "optko": ["어느 것이든 더 쉬운 것으로요.", "초콜릿으로 합시다.", "보통 30분 이내로요."], "ans": 0, "audio": "Test07_27.mp3"}, {"n": 28, "part": 2, "q": "Who has agreed to travel to San Francisco for the medical convention?", "qko": "누가 의학 컨벤션을 위해 샌프란시스코에 가기로 동의했나요?", "opts": ["Well, only after the convention ended.", "The trip took almost five days.", "Isn't Dr. Kumar planning to go?"], "optko": ["음, 컨벤션이 끝난 이후에만요.", "여행은 거의 5일이 걸렸어요.", "Dr. Kumar가 가려고 계획 중이지 않나요?"], "ans": 2, "audio": "Test07_28.mp3"}, {"n": 29, "part": 2, "q": "How will the marketing director choose which intern to hire?", "qko": "마케팅 부장이 어느 인턴을 고용할지 어떻게 결정할까요?", "opts": ["Would you rather have a direct flight?", "She already gave the job to Steven Davies.", "The internship lasts three months."], "optko": ["직항편을 이용하시겠어요?", "그녀는 이미 Steven Davies에게 그 일자리를 주었어요.", "인턴십은 세 달 동안 진행됩니다."], "ans": 1, "audio": "Test07_29.mp3"}, {"n": 30, "part": 2, "q": "A box was just dropped off for Rita Fritz.", "qko": "Rita Fritz를 위한 상자가 방금 배달되었어요.", "opts": ["Can you bring it to her?", "Check rates from other shipping companies.", "She never had a chance to taste them."], "optko": ["그것을 그녀에게 가져다주실 수 있나요?", "다른 운송 회사의 요금을 확인해보세요.", "그녀는 그것들을 맛볼 기회가 전혀 없었어요."], "ans": 0, "audio": "Test07_30.mp3"}, {"n": 31, "part": 2, "q": "Can a photo of our shop be added to our Web site?", "qko": "우리 가게의 사진이 웹사이트에 추가될 수 있나요?", "opts": ["I'll check the online version.", "Yes. That's simple to do.", "They rent cameras, too."], "optko": ["제가 온라인 버전을 확인해 볼게요.", "네, 그것은 하기가 간단해요.", "그들은 카메라도 빌려줘요."], "ans": 1, "audio": "Test07_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Au", "audio": "Test07_32-34.mp3", "qs": [{"n": 32, "q": "What does the woman say an article is about?", "opts": ["International trade laws", "Stock market performance", "Overseas production", "Marketing methods"], "ans": 2, "ko": "여자는 기사가 무엇에 관한 것이라고 말하는가?"}, {"n": 33, "q": "What does the man mention about competitors?", "opts": ["They launched some products.", "They conducted customer surveys.", "They might introduce new design plans.", "They might reduce prices."], "ans": 3, "ko": "남자는 경쟁업체들에 관해 무엇을 언급하는가?"}, {"n": 34, "q": "What does the woman suggest doing?", "opts": ["Holding a press conference", "Creating a campaign", "Postponing a gathering", "Finding a new distributor"], "ans": 1, "ko": "여자는 무엇을 하라고 제안하는가?"}], "script": [{"sp": "W", "en": "I read an article this morning that was published in Business Quarterly magazine. It highlighted the fact that more companies are manufacturing TV screens abroad because doing so is much cheaper.", "ko": "저는 Business Quarterly 잡지에 실린 기사를 오늘 아침에 읽었어요. 그것은 TV 스크린을 해외에서 제조하는 것이 훨씬 더 저렴하기 때문에 더 많은 회사들이 이렇게 하고 있다는 사실을 강조했어요."}, {"sp": "M", "en": "Hmm . . . That might create a problem for us if our competitors end up lowering their prices. If they do, I suppose we'll have to think of ways to encourage customers to buy our domestically produced goods.", "ko": "흠... 우리의 경쟁업체들이 결국 가격을 낮추게 되면 그것은 우리에게 문제가 될 수 있겠네요. 만약 그들이 그렇게 한다면, 저는 고객들이 국내에서 생산된 우리 제품을 구매하도록 장려할 방법들을 구상해야 할 거라고 생각해요."}, {"sp": "W", "en": "What if we emphasize how our goods lead to more high-paying jobs in the United Kingdom? We could launch a marketing campaign about it.", "ko": "우리 상품들이 어떻게 영국의 더 많은 고임금 일자리들을 야기하는지 강조하면 어떨까요? 우리는 그것에 대해 마케팅 캠페인을 시작할 수 있을 거예요."}, {"sp": "M", "en": "That's a great plan. I think consumers here would respond well to that message.", "ko": "훌륭한 계획이네요. 저는 이곳의 고객들이 그 메시지에 좋은 반응을 보일 거라고 생각해요."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "M-Ca / W-Br", "audio": "Test07_35-37.mp3", "qs": [{"n": 35, "q": "What are the speakers mainly discussing?", "opts": ["A network problem", "A Web site design", "A software release", "A supply shortage"], "ans": 0, "ko": "화자들은 주로 무엇에 관해 이야기하고 있는가?"}, {"n": 36, "q": "What does the woman say her supervisor is doing now?", "opts": ["Ordering a replacement device", "Speaking with a department head", "Requesting a product upgrade", "E-mailing a service center"], "ans": 1, "ko": "여자는 그녀의 관리자가 지금 무엇을 하고 있다고 말하는가?"}, {"n": 37, "q": "What does the man say he will do?", "opts": ["Head to a manager's office", "Restart a computer", "Propose a change", "Complete some repairs"], "ans": 2, "ko": "남자는 무엇을 할 것이라고 말하는가?"}], "script": [{"sp": "M", "en": "Louise, I can't access any Web sites on my computer. Do you know what the problem might be?", "ko": "Louise, 제 컴퓨터로 어느 웹사이트에도 접속할 수 없어요. 문제가 무엇일지 아시나요?"}, {"sp": "W", "en": "All staff are having the same issue. Our supervisor is discussing the matter over the phone with the IT department head now.", "ko": "모든 직원들이 같은 문제를 겪고 있어요. 저희 관리자가 지금 IT 부서장과 전화로 그 문제에 대해 논의하고 있어요."}, {"sp": "M", "en": "This is very frustrating . . . It's the third time this month that we've had Internet issues.", "ko": "너무 답답하네요... 우리가 인터넷 문제를 겪은 게 이번 달에만 세 번째예요."}, {"sp": "W", "en": "I know. I suspect it's the Internet provider we're using. Maybe the IT staff should consider switching back to our previous provider.", "ko": "알아요. 저는 우리가 이용하고 있는 인터넷 제공업체 때문이라고 생각해요. 어쩌면 IT 직원은 우리의 예전 제공업체로 되돌아가는 것을 고려해야 할 것 같아요."}, {"sp": "M", "en": "I agree. We never had issues like this in the past. I think I'll send out an e-mail making the suggestion now.", "ko": "저도 동의해요. 이전에는 이런 문제가 전혀 없었거든요. 지금 그걸 제안하는 이메일을 보내야겠어요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Am", "audio": "Test07_38-40.mp3", "qs": [{"n": 38, "q": "According to the man, what happened recently?", "opts": ["An establishment was opened.", "A promotion expired.", "A worker resigned.", "A prize was given away."], "ans": 0, "ko": "남자에 따르면, 최근에 무슨 일이 일어났는가?"}, {"n": 39, "q": "What problem does the man mention?", "opts": ["A product line is not selling well.", "A customer has made a complaint.", "An ingredient is no longer fresh.", "A branch manager has not returned."], "ans": 0, "ko": "남자는 어떤 문제를 언급하는가?"}, {"n": 40, "q": "What does the man say he will do?", "opts": ["Refill a display case with sandwiches", "Extend the operating hours of a business", "Install an additional cash register", "Ask an employee to distribute samples"], "ans": 3, "ko": "남자는 무엇을 할 것이라고 말하는가?"}], "script": [{"sp": "M", "en": "Our coffee shop has had good sales so far since opening last week.", "ko": "저희 커피숍은 지난주 개점 이후 지금까지 상당한 판매량을 유지해 왔어요."}, {"sp": "W", "en": "True, but I think we can do more to promote our line of freshly made sandwiches.", "ko": "맞아요, 하지만 저는 우리의 갓 만들어진 샌드위치 종류들을 홍보하기 위해 우리가 더 많은 것들을 할 수 있다고 생각해요."}, {"sp": "M", "en": "Yeah, I've seen many customers just walk past the section where they're displayed. Do you have any suggestions for advertising them better?", "ko": "맞아요, 저는 고객들이 그것들이 진열된 구역을 그냥 지나치는 것을 봐왔어요. 당신은 그것들을 더 잘 광고하기 위한 의견이 있나요?"}, {"sp": "W", "en": "We could give out samples at our storefront.", "ko": "우리는 가게 앞에서 샘플을 나누어 줄 수 있을 거예요."}, {"sp": "M", "en": "Who should that task be assigned to, though? Both of us have other work to do, and Sarah is operating the cash register.", "ko": "그렇지만 그 일이 누구에게 배정되어야 할까요? 우리 둘 다 모두 다른 할 일이 있고, Sarah는 금전 등록기를 관리하고 있어요."}, {"sp": "W", "en": "Isn't Andy going to be starting his shift at 11 A.M.?", "ko": "Andy가 오전 11시에 교대 근무를 시작하지 않나요?"}, {"sp": "M", "en": "Oh, right. I forgot. I'll ask him to do it once he arrives.", "ko": "아, 맞아요. 깜박했네요. 그가 도착하면 제가 그에게 그것을 하도록 요청할게요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "M1-Ca / W-Br / M2-Au", "audio": "Test07_41-43.mp3", "qs": [{"n": 41, "q": "Where do the speakers most likely work?", "opts": ["At a gardening store", "At a fire station", "At a train station", "At an apartment complex"], "ans": 1, "ko": "화자들은 어디에서 일하는 것 같은가?"}, {"n": 42, "q": "What does the woman mention about Justin?", "opts": ["He has asked for assistance.", "He requires more training.", "He will make an announcement.", "He recently moved an item."], "ans": 3, "ko": "여자는 Justin에 관해 무엇을 언급하는가?"}, {"n": 43, "q": "What does Justin offer to do?", "opts": ["Share an idea with a manager", "Hang up another hose", "Lead coworkers to a location", "Make room for some goods"], "ans": 2, "ko": "Justin은 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "M1", "en": "Sharon, I know we're supposed to put the extra hoses for the fire trucks in a new place here, but I was never told where. Can you help me out?", "ko": "Sharon, 우리가 여기 새로운 장소에 여분의 소방차용 호스를 두어야 한다는 것을 알고 있지만, 어디인지는 전혀 들은 적이 없어요. 저를 좀 도와주실 수 있나요?"}, {"sp": "W", "en": "I was actually wondering the same thing. Our chief announced the change yesterday, but I wasn't here when he did. I saw Justin moving a hose this morning, though.", "ko": "저도 사실 같은 것을 궁금해하고 있었어요. 저희 과장님이 어제 변경 사항을 알려주었지만 그가 이야기할 때는 저는 여기에 없었어요. 그런데 오늘 아침에 Justin이 호스를 옮기는 걸 봤어요."}, {"sp": "M2", "en": "Did someone just mention my name?", "ko": "누군가 방금 제 이름을 언급했나요?"}, {"sp": "M1", "en": "Justin, hey. Sharon and I aren't sure where to put hoses that aren't being used.", "ko": "Justin, 안녕하세요. Sharon과 저는 사용되지 않는 호스를 어디에 둘지 잘 모르겠어요."}, {"sp": "M2", "en": "There's a spot in our smaller garage where they're being kept. Why don't I show you two?", "ko": "작은 차고에 그것들이 보관되는 자리가 있어요. 제가 두 분께 보여드릴까요?"}, {"sp": "M1", "en": "That'd be great. Thanks.", "ko": "그거 좋겠네요. 감사해요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Am", "audio": "Test07_44-46.mp3", "qs": [{"n": 44, "q": "Where is the conversation most likely taking place?", "opts": ["At a tourist information center", "At a clothing retail outlet", "At a language academy", "At a manufacturing plant"], "ans": 3, "ko": "대화는 어디에서 일어나고 있는 것 같은가?"}, {"n": 45, "q": "What does the woman suggest?", "opts": ["Requesting some help", "Changing a speech", "Hiring a guide", "Reviewing some research"], "ans": 0, "ko": "여자는 무엇을 제안하는가?"}, {"n": 46, "q": "What will the man most likely do in 30 minutes?", "opts": ["Restock some clothing", "Participate in a meeting", "Read over an application", "Speak to a client"], "ans": 1, "ko": "남자는 30분 뒤에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Hey, Matilda. In two weeks, a group of business students from Madrid University will visit here to tour this factory and study our clothing production process. I heard that most of them only speak Spanish. Do you know of any interpreters we can hire?", "ko": "안녕하세요, Matilda. 2주 뒤에, 마드리드 대학의 경영학과 학생들이 이 공장을 견학하고 우리의 의류 생산 과정을 연구하기 위해 이곳을 방문할 거예요. 저는 그들 중 대부분이 스페인어만 할 줄 안다고 들었어요. 우리가 고용할 수 있는 통역사를 알고 있나요?"}, {"sp": "W", "en": "Hiring an interpreter will be very expensive. Instead, let's ask one of our staff members for assistance. Elena from the customer service team often handles phone calls from Spanish-speaking customers. So, she may be able to help.", "ko": "통역사를 고용하는 것은 매우 비쌀 거예요. 대신, 우리 직원 중 한 명에게 도움을 요청하도록 하죠. 고객 서비스팀의 Elena는 스페인어를 사용하는 고객들의 전화를 종종 처리해요. 그러니까 그녀가 도울 수 있을 거예요."}, {"sp": "M", "en": "Excellent idea. We'll be taking part in a meeting in half an hour. I'll bring it up with her then.", "ko": "훌륭한 생각이네요. 우리는 30분 뒤에 회의에 참석할 거예요. 제가 그때 그녀에게 이걸 얘기할게요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "M-Ca / W-Br", "audio": "Test07_47-49.mp3", "qs": [{"n": 47, "q": "Who most likely are the speakers?", "opts": ["Safety inspectors", "Laboratory workers", "Clothing designers", "Purchasing managers"], "ans": 1, "ko": "화자들은 누구인 것 같은가?"}, {"n": 48, "q": "What problem does the woman mention?", "opts": ["A deadline is tight.", "A branch has moved.", "A worker is late.", "A warranty has expired."], "ans": 0, "ko": "여자는 무슨 문제를 언급하는가?"}, {"n": 49, "q": "What does the woman give the man?", "opts": ["A new uniform", "A closet key", "A credit card", "An area map"], "ans": 2, "ko": "여자는 남자에게 무엇을 주는가?"}], "script": [{"sp": "M", "en": "Some of the protective clothing in our laboratory's storage closet is getting worn out, and a group of new hires start next week. They'll need fresh garments.", "ko": "우리 연구실의 수납장에 있는 보호복 중 일부가 닳아 해지고 있고, 다음 주에 신규 채용자들이 일을 시작하게 돼요. 그들은 새로운 의복이 필요할 거예요."}, {"sp": "W", "en": "Hmm . . . Well, we won't have time to order them through our supplier. That usually takes two to three weeks for delivery. But maybe there's a faster method.", "ko": "흠... 글쎄요, 우리는 공급 회사를 통해 주문할 시간이 없을 거예요. 그건 배달에 보통 2~3주가 걸려요. 하지만 아마 더 빠른 방법이 있을 수도 있어요."}, {"sp": "M", "en": "Actually, I know of a uniform store located downtown. If we're only getting a few items, I'm sure we can find what we need there.", "ko": "사실, 저는 시내에 있는 유니폼 가게를 알고 있어요. 우리가 약간의 물품들만 산다면, 우리가 필요한 것을 그곳에서 찾을 수 있을 거라고 확신해요."}, {"sp": "W", "en": "Great. Why don't you go to that store later today? Here, charge whatever you get to this company credit card. Thanks a lot.", "ko": "좋아요. 당신이 오늘 늦게 그 가게에 가는 게 어때요? 여기요, 구입하는 것은 무엇이든 이 회사 신용 카드에 청구하세요. 정말 고마워요."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Am", "audio": "Test07_50-52.mp3", "qs": [{"n": 50, "q": "What does the man say about Ms. Fleming?", "opts": ["She will be leaving a company.", "She will oversee a division expansion.", "She will modify an accounting policy.", "She will study the cause of a sales decline."], "ans": 0, "ko": "남자는 Ms. Fleming에 관해 무엇을 말하는가?"}, {"n": 51, "q": "What did the man speak about with the CEO?", "opts": ["An evaluation", "A promotion", "An orientation", "A celebration"], "ans": 1, "ko": "남자는 최고 경영자와 무엇에 관해 이야기했는가?"}, {"n": 52, "q": "What does the man mean when he says, \"I'm quite comfortable where I am\"?", "opts": ["A conference room will not be used.", "A workspace will not be moved.", "A position will be turned down.", "A housing search will be canceled."], "ans": 1, "ko": "남자는 \"저는 제가 있는 곳이 꽤나 편해요\"라고 말할 때 무엇을 의도하는가?"}], "script": [{"sp": "M", "en": "Hi, Christi. Have you heard the news? Ms. Fleming is going to retire a year earlier than expected. She shared her decision with our CEO this morning.", "ko": "안녕하세요, Christi. 소식 들으셨나요? Ms. Fleming이 예상보다 일 년 더 일찍 퇴직할 거래요. 그녀는 오늘 아침 그녀의 결정에 대해 최고 경영자와 이야기했어요."}, {"sp": "W", "en": "Really? That will be a big loss for our department.", "ko": "정말이요? 그것은 우리 부서에 큰 손실이 될 거예요."}, {"sp": "M", "en": "Yeah, I agree . . . But that's not all. I had a meeting with our CEO this morning, and he offered me Ms. Fleming's job. I got promoted to the position of department manager.", "ko": "맞아요, 동의해요... 하지만 그게 전부가 아니에요. 저는 오늘 아침에 최고 경영자와 회의를 했는데, 그가 Ms. Fleming의 자리를 제게 제안했어요. 저는 부서장직으로 승진했어요."}, {"sp": "W", "en": "Congratulations! I'm sure you'll do an excellent job. And you'll have a great view of the city from Ms. Fleming's office.", "ko": "축하해요! 저는 당신이 잘 해낼 것이라고 확신해요. 그리고 Ms. Fleming의 사무실에서 도시의 멋진 경관을 볼 수 있겠네요."}, {"sp": "M", "en": "I'm quite comfortable where I am . . . I figure creating another conference room would be more useful for the department.", "ko": "저는 제가 있는 곳이 꽤나 편해요... 저는 또 하나의 회의실을 만드는 것이 부서에 더 유용할 거라고 생각해요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Cn", "audio": "Test07_53-55.mp3", "qs": [{"n": 53, "q": "Where is the conversation most likely taking place?", "opts": ["At a bookstore", "At an electronics store", "At a bank", "At a subway station"], "ans": 2, "ko": "대화는 어디에서 일어나고 있는 것 같은가?"}, {"n": 54, "q": "What does the man ask for?", "opts": ["A train route", "An item description", "A business address", "A telephone number"], "ans": 1, "ko": "남자는 무엇을 요청하는가?"}, {"n": 55, "q": "Why will the man send out an e-mail?", "opts": ["To express gratitude", "To provide instructions", "To explain an error", "To inquire about a change"], "ans": 1, "ko": "남자는 왜 이메일을 보낼 것인가?"}], "script": [{"sp": "W", "en": "Excuse me. I was here about an hour ago to open a new savings account. I think I accidentally left my cell phone here. Has anyone found it?", "ko": "실례합니다. 저는 신규 저축 예금을 개설하려고 약 한 시간 전에 이곳에 있었어요. 제가 우연히 여기에 제 휴대 전화를 두고 간 것 같아요. 누군가가 그것을 발견했나요?"}, {"sp": "M", "en": "What does the device look like?", "ko": "그 기기가 어떻게 생겼나요?"}, {"sp": "W", "en": "It's black and has a brown leather case.", "ko": "검정색이고, 갈색 가죽 케이스가 있어요."}, {"sp": "M", "en": "Let me check our lost and found box . . . um . . . Sorry, I don't see anything like that here. Are you sure you didn't misplace it elsewhere?", "ko": "제가 분실물 보관함을 확인해 보겠습니다… 음… 죄송합니다, 여기에 그런 것은 안 보이네요. 그것을 다른 곳에 잘못 두지 않은 게 확실한가요?"}, {"sp": "W", "en": "Well, I went to the library earlier this morning. I plan to check there next.", "ko": "글쎄요, 오늘 아침 일찍 도서관에 갔었어요. 다음으로 그곳을 확인해볼 계획이에요."}, {"sp": "M", "en": "OK. And I'll e-mail our staff and tell them to immediately report it if they find anything.", "ko": "알겠습니다. 그리고 제가 저희 직원들에게 이메일을 보내서 그들이 무언가라도 발견하면 즉시 보고하라고 하겠습니다."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "M-Cn / W-Br", "audio": "Test07_56-58.mp3", "qs": [{"n": 56, "q": "What does the man ask about?", "opts": ["A recording sample", "A legal document", "A hiring situation", "A travel plan"], "ans": 2, "ko": "남자는 무엇에 대해 문의하는가?"}, {"n": 57, "q": "What does the woman imply when she says, \"I think it would be worth it\"?", "opts": ["She wants to renew a contract.", "She approves of a candidate.", "She understands a problem.", "She agrees with a client."], "ans": 1, "ko": "여자는 \"저는 그럴 가치가 있을 거라고 생각해요\"라고 말할 때 무엇을 의도하는가?"}, {"n": 58, "q": "What problem does the man mention?", "opts": ["A coworker was not consulted.", "An assessment was incorrect.", "A budget is limited.", "A project is delayed."], "ans": 2, "ko": "남자는 무슨 문제를 언급하는가?"}], "script": [{"sp": "M", "en": "Vanessa, have you found a suitable voice actress for the radio commercial our company is producing for Crestbrook Department Store? We need to hire somebody soon.", "ko": "Vanessa, 우리 회사가 Crestbrook 백화점을 위해 제작하는 라디오 광고에 적합한 성우를 찾으셨나요? 우리는 빨리 누군가를 고용해야 해요."}, {"sp": "W", "en": "Actually, I just finished interviewing a woman over the phone.", "ko": "사실, 방금 전화로 한 여성 분의 면접을 마쳤어요."}, {"sp": "M", "en": "Over the phone? Why didn't you speak to her in person?", "ko": "전화로요? 왜 그녀와 직접 이야기하지 않으셨나요?"}, {"sp": "W", "en": "She lives in another city. Uh, Detroit . . .", "ko": "그녀는 다른 도시에 살아요. 어, 디트로이트요…"}, {"sp": "M", "en": "Hmm . . . So, that means we would have to reimburse her for travel and accommodation if we hired her, right?", "ko": "흠… 그럼, 만약 우리가 그녀를 고용한다면 그녀에게 교통과 숙소에 대해 변제해줘야 한다는 뜻이네요, 그렇죠?"}, {"sp": "W", "en": "I think it would be worth it. She's done several similar projects in the past.", "ko": "저는 그럴 가치가 있을 거라고 생각해요. 그녀는 과거에 여러 비슷한 프로젝트들을 수행했거든요."}, {"sp": "M", "en": "OK. I trust your judgment. But keep in mind that we can only provide up to $500 for these expenses.", "ko": "알았어요. 당신의 판단을 믿어요. 하지만 이러한 지출에는 500달러까지만 제공할 수 있다는 것을 유념하세요."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "M-Cn / W1-Am / W2-Br", "audio": "Test07_59-61.mp3", "qs": [{"n": 59, "q": "Where does the man most likely work?", "opts": ["In a supermarket", "In a café", "In a warehouse", "In a bakery"], "ans": 3, "ko": "남자는 어디에서 일하는 것 같은가?"}, {"n": 60, "q": "What information does Beth provide?", "opts": ["The location of an office", "The time of an event", "The name of a manager", "The amount of a charge"], "ans": 1, "ko": "Beth는 무슨 정보를 제공하는가?"}, {"n": 61, "q": "What does the man offer to do for an extra fee?", "opts": ["Expedite an order", "Change a service", "Upgrade a product", "Deliver an item"], "ans": 3, "ko": "남자는 추가 요금으로 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "M", "en": "Welcome to Paterson's Baked Goods! How can I help you?", "ko": "Paterson's Baked Goods에 오신 것을 환영합니다! 어떻게 도와드릴까요?"}, {"sp": "W1", "en": "It's my supervisor's birthday tomorrow, and she wants a strawberry cake. But she doesn't eat dairy.", "ko": "내일이 제 상사의 생일인데, 그녀는 딸기 케이크를 원해요. 하지만 그녀는 유제품을 먹지 않아요."}, {"sp": "M", "en": "No problem. I can make one without any milk or butter. It won't be ready until tomorrow at 11 A.M., though. Is that OK?", "ko": "전혀 문제되지 않아요. 저는 우유나 버터 없이 만들어드릴 수 있어요. 하지만 내일 오전 11시나 되어야 준비가 될 예정이에요. 괜찮으신가요?"}, {"sp": "W1", "en": "Let me call a coworker quickly to check . . . Hello, Beth. When will the party for Ms. Larson be held?", "ko": "동료에게 빨리 전화해서 확인해볼게요… 여보세요, Beth. Ms. Larson을 위한 파티가 언제 열리나요?"}, {"sp": "W2", "en": "Um, at 1 P.M. Once everyone returns from lunch.", "ko": "음, 오후 1시에요. 모두가 점심 식사에서 돌아오면요."}, {"sp": "W1", "en": "Thanks . . . Uh, 11 A.M. is fine.", "ko": "고마워요… 어, 오전 11시 괜찮아요."}, {"sp": "M", "en": "Great. Would you like to pick it up? It can also be brought to your office for a $10 charge.", "ko": "좋아요. 손님께서 찾아가시겠어요? 10달러 요금으로 손님의 사무실로 가져다 드릴 수도 있어요."}, {"sp": "W1", "en": "I'll come get it myself.", "ko": "제가 직접 찾으러 올게요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "M-Au / W-Br", "audio": "Test07_62-64.mp3", "qs": [{"n": 62, "q": "What problem does the man mention?", "opts": ["Some participants have not arrived.", "Some equipment was not installed.", "A room is occupied.", "An elevator is out of order."], "ans": 0, "ko": "남자는 무슨 문제를 언급하는가?"}, {"n": 63, "q": "Who most likely is the man?", "opts": ["A senior manager", "A new employee", "A technician", "A receptionist"], "ans": 1, "ko": "남자는 누구인 것 같은가?"}, {"n": 64, "q": "Look at the graphic. Where is a meeting being held?", "opts": ["In Room 1401", "In Room 1402", "In Room 1403", "In Room 1404"], "ans": 3, "ko": "시각 자료를 보시오. 회의는 어디에서 열리고 있는가?"}], "script": [{"sp": "M", "en": "Pardon me. I'm supposed to participate in an orientation session organized by the human resources department. It should've started at 1:30 P.M., but it's 1:35 P.M. now, and no one has arrived yet. That's the main conference room over there, right?", "ko": "실례합니다. 저는 인사부에서 주최하는 오리엔테이션에 참석하기로 되어 있어요. 오후 1시 30분에 시작했어야 하는데, 지금 오후 1시 35분이고, 아직 아무도 도착하지 않았어요. 저쪽이 대회의실이죠, 그렇죠?"}, {"sp": "W", "en": "Yes, it is. But, your meeting was moved to one of our other conference rooms.", "ko": "네, 그렇습니다. 하지만 당신의 회의는 저희의 다른 회의실 들 중 하나로 옮겨졌어요."}, {"sp": "M", "en": "Oh, thanks. I'm still settling in here since it's my first day of work. Can you tell me where I should go?", "ko": "아, 감사해요. 오늘이 근무 첫날이라 저는 이곳에 아직 적응하는 중이에요. 제가 어디로 가야 하는지 알려주실 수 있나요?"}, {"sp": "W", "en": "Sure. Head to the 14th floor. When you get off the elevator on that floor, go right. The meeting is taking place in the space directly across from the break room.", "ko": "물론이죠. 14층으로 가세요. 그 층에서 엘리베이터에서 내리셔서, 오른쪽으로 가세요. 회의는 휴게실 바로 맞은편에 있는 장소에서 진행되고 있어요."}], "gimg": "hk_t7_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "M-Cn / W-Am", "audio": "Test07_65-67.mp3", "qs": [{"n": 65, "q": "What is mentioned about Coral Sea?", "opts": ["Its first performance is on Saturday.", "It was written by a local playwright.", "It is playing only on the weekend.", "Its leading actor will retire next year."], "ans": 0, "ko": "Coral Sea에 관해 무엇이 언급되는가?"}, {"n": 66, "q": "Look at the graphic. Where will the man most likely sit?", "opts": ["In Section 1", "In Section 2", "In Section 3", "In Section 4"], "ans": 1, "ko": "시각 자료를 보시오. 남자는 어디에 앉을 것 같은가?"}, {"n": 67, "q": "What does the man request?", "opts": ["A seating chart", "A show program", "A proof of purchase", "A confirmation number"], "ans": 2, "ko": "남자는 무엇을 요청하는가?"}], "script": [{"sp": "M", "en": "Hi. I'm interested in seeing the musical Coral Sea. Are there any tickets available for the opening show on Saturday?", "ko": "안녕하세요. 저는 뮤지컬 Coral Sea를 보는 것에 관심이 있어요. 구할 수 있는 토요일 개막 공연 티켓이 있나요?"}, {"sp": "W", "en": "A few left, but they're going fast. The leading actor was nominated for several awards last year, so there is a lot of interest in the play.", "ko": "조금 남았는데, 그것들은 빨리 나가고 있습니다. 주연 배우가 작년에 여러 상의 후보로 지명되어서, 연극에 다들 관심이 많으세요."}, {"sp": "M", "en": "Great, I'm glad some seats are still available. I'd like two that are next to each other and as close to the stage as possible.", "ko": "좋아요, 아직 몇 개의 자리를 구할 수 있다니 기뻐요. 저는 옆에 나란히 앉을 수 있고 무대와 최대한 가까운 두 자리를 원해요."}, {"sp": "W", "en": "OK. And will you be paying with cash or credit card?", "ko": "알겠습니다. 그리고 현금으로 지불하실 건가요, 아니면 신용 카드로 지불하실 건가요?"}, {"sp": "M", "en": "You can run this card. And I need a receipt, please.", "ko": "이 카드로 하시면 돼요. 그리고 저는 영수증이 필요해요."}], "gimg": "hk_t7_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "M-Cn / W-Am", "audio": "Test07_68-70.mp3", "qs": [{"n": 68, "q": "What problem does the man mention?", "opts": ["Some students do not qualify for a refund.", "A class is currently full.", "A test was too difficult.", "Enrollment numbers are not available online."], "ans": 3, "ko": "남자는 어떤 문제를 언급하는가?"}, {"n": 69, "q": "Look at the graphic. How much will the man most likely pay?", "opts": ["$105", "$110", "$115", "$120"], "ans": 2, "ko": "시각 자료를 보시오. 남자는 얼마를 지불할 것 같은가?"}, {"n": 70, "q": "What will the man probably do next?", "opts": ["Provide payment information", "Show a driver's license", "Speak with a supervisor", "Indicate some preferences"], "ans": 0, "ko": "남자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Good morning. My name is Aaron Vargas. Do you still have room in tomorrow's basic driving skills class? Your academy's Web site doesn't show if there is availability or not.", "ko": "안녕하세요. 제 이름은 Aaron Vargas입니다. 내일 초보 운전 기술 수업에 아직 자리가 있나요? 당신의 학원 웹사이트는 이용할 수 있는지 없는지를 보여주지 않네요."}, {"sp": "W", "en": "We still have a couple of slots open. Would you like to reserve one?", "ko": "아직 몇 개의 자리가 비어 있습니다. 예약하시겠어요?"}, {"sp": "M", "en": "Yes, please.", "ko": "네, 그렇게 해주세요."}, {"sp": "W", "en": "OK. And just so you know, new students get a slight discount, including for the basic driving course. Have you enrolled with us before?", "ko": "알겠습니다. 그리고 아시겠지만, 신규 학생들은 초보 운전 코스를 포함해 약간의 할인을 받습니다. 이전에 저희에게 등록하신 적이 있나요?"}, {"sp": "M", "en": "I took your test preparation class last month.", "ko": "지난달에 시험 준비 수업을 들었어요."}, {"sp": "W", "en": "In that case, you'll have to pay the full amount. Now, I'll need a credit card number as students are charged in advance for classes.", "ko": "그런 경우에는 전액을 지불하셔야 합니다. 자, 학생들은 수업료를 미리 지불해야 하기 때문에 저는 신용 카드 번호가 필요합니다."}], "gimg": "hk_t7_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "M-Cn", "audio": "Test07_71-73.mp3", "qs": [{"n": 71, "q": "Where is the talk taking place?", "opts": ["At a grocery store", "At a restaurant", "In a banquet hall", "In an office"], "ans": 1, "ko": "담화는 어디에서 일어나고 있는가?"}, {"n": 72, "q": "What is mentioned about Michael Trager?", "opts": ["He was recently hired.", "He sampled different products.", "He did not receive training.", "He does not like some decorations."], "ans": 0, "ko": "Michael Trager에 관해 무엇이 언급되는가?"}, {"n": 73, "q": "According to the speaker, what will happen on October 23?", "opts": ["A business owner will visit.", "A facility will be temporarily closed.", "Staff members will be surveyed.", "New offerings will be made available."], "ans": 3, "ko": "화자에 따르면, 10월 23일에 무엇이 일어날 것인가?"}], "script": [{"sp": "M", "en": "Thank you all for coming in before we open the bistro for lunch. I want to give everyone an update on the latest menu changes. As you all know, the owners would like to offer a variety of traditional Italian foods in addition to our pizzas. And ever since Chef Michael Trager joined our team last week, our cooks have been working on some new recipes. This morning you'll get to sample the menu items and provide feedback about the dishes, which we'll begin serving on October 23.", "ko": "점심 영업을 위해 우리가 식당을 열기 전에 모두 와주셔서 감사합니다. 저는 모두에게 최근의 메뉴 변경에 대한 최신 소식을 알려드리고 싶습니다. 모두 아시다시피, 소유주들은 피자와 더불어 다양한 전통 이탈리안 음식들을 제공하고 싶어 합니다. 그리고 지난주에 Michael Trager 셰프가 우리 팀에 합류한 이후로, 우리 요리사들은 새로운 요리법들에 대한 작업을 해왔습니다. 오늘 아침에 여러분은 우리가 10월 23일에 제공하기 시작할 메뉴를 시식하고, 그 요리들에 대한 의견을 제공하게 되실 겁니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test07_74-76.mp3", "qs": [{"n": 74, "q": "Why is the speaker calling?", "opts": ["To verify personal information", "To change a work schedule", "To apologize for an accident", "To respond to an inquiry"], "ans": 3, "ko": "화자는 왜 전화를 하고 있는가?"}, {"n": 75, "q": "What does the speaker say the listener must do?", "opts": ["Pay for a special service", "Send out another e-mail", "Visit a business in person", "Have a prescription renewed"], "ans": 2, "ko": "화자는 청자가 무엇을 해야 한다고 말하는가?"}, {"n": 76, "q": "Who most likely is Vincent Mitchel?", "opts": ["A safety inspector", "A medical doctor", "A delivery person", "A store supervisor"], "ans": 3, "ko": "Vincent Mitchel은 누구인 것 같은가?"}], "script": [{"sp": "W", "en": "This message is for Derek Hastings. My name is Judy, and I work at Blue Circle Pharmacy. I've had a chance to listen to the voice mail you left yesterday. Regarding your question, we're unable to mail regularly refilled prescriptions to your home. We don't offer this service for safety and liability reasons. So you'll have to pick them up at our store yourself. If you have any other questions about the matter, feel free to contact Vincent Mitchel, my manager.", "ko": "이 메시지는 Derek Hastings를 위한 것입니다. 제 이름은 Judy이고, 저는 Blue Circle 약국에서 일합니다. 저는 귀하가 어제 남기신 음성 메시지를 들을 기회가 있었습니다. 귀하의 질문에 관해서, 저희는 정기적으로 처방약을 다시 조제하여 댁으로 발송해드릴 수 없습니다. 저희는 안전 및 법적 책임 사유들로 인해 이 서비스를 제공하지 않습니다. 따라서 손님께서 저희 가게로 직접 가지러 오셔야 할 것입니다. 이 문제에 대해 다른 문의 사항이 있으시다면, 제 관리자인 Vincent Mitchel에게 부담 없이 연락하십시오."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "M-Cn", "audio": "Test07_77-79.mp3", "qs": [{"n": 77, "q": "Who most likely is the speaker?", "opts": ["A bus driver", "A zookeeper", "A photographer", "A tour guide"], "ans": 3, "ko": "화자는 누구인 것 같은가?"}, {"n": 78, "q": "What will listeners do before taking a shuttle?", "opts": ["Eat a meal", "Pose for a picture", "Pay for passes", "Return some equipment"], "ans": 0, "ko": "청자들은 버스에 타기 전에 무엇을 할 것인가?"}, {"n": 79, "q": "What does the speaker mean when he says, \"We've got a long afternoon ahead of us\"?", "opts": ["A drive will last all morning.", "A lot of hiking will take place.", "Numerous breaks are planned.", "Arriving early is recommended."], "ans": 1, "ko": "화자는 \"우리에게는 긴 오후가 예정되어 있다\"라고 말할 때 무엇을 의도하는가?"}], "script": [{"sp": "M", "en": "OK, let's go over today's schedule for exploring Ridge Park. First of all, we'll head over to the Ridge Wildlife Museum to learn about the wide range of animals that reside in the park. Following that, we'll break for lunch. Once everyone is finished, we'll ride a shuttle bus to the forest preserve. It's a great area for photos. Now, I hope you're all wearing comfortable shoes. We've got a long afternoon ahead of us, and many of the paths are pretty rocky.", "ko": "자, Ridge 공원을 탐험하는 오늘의 일정을 점검합시다. 우선, 우리는 공원에 거주하는 다양한 동물들에 대해 배우기 위해 Ridge 야생 동물 박물관으로 출발할 것입니다. 뒤이어, 점심을 먹을 거예요. 모든 분들이 식사를 마치시면, 보존림으로 가는 셔틀 버스를 탈 것입니다. 그곳은 사진 촬영을 하기 좋은 장소입니다. 자, 여러분 모두 편한 신발을 신고 계시기를 바랍니다. 우리에게는 긴 오후가 예정되어 있으며, 많은 길들이 꽤 험난합니다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test07_80-82.mp3", "qs": [{"n": 80, "q": "What will some listeners do next week?", "opts": ["Promote some bicycles", "Test out new merchandise", "Take part in a fund-raiser", "Rearrange some desks"], "ans": 2, "ko": "일부 청자들은 다음 주에 무엇을 할 것인가?"}, {"n": 81, "q": "What did Marcelle do yesterday?", "opts": ["Revised a guest list", "Finalized some plans", "Collected some fees", "Passed out some clothing"], "ans": 3, "ko": "Marcelle은 어제 무엇을 했는가?"}, {"n": 82, "q": "What does the speaker mean when he says, \"Come by my office at your convenience\"?", "opts": ["Money will be provided.", "Presentations will be given.", "Evaluations will be completed.", "Documents will be reviewed."], "ans": 0, "ko": "화자는 \"편하실 때 제 사무실로 오세요\"라고 말할 때 무엇을 의도하는가?"}], "script": [{"sp": "M", "en": "Before we finish up, let's discuss the charity bike ride that some of you will be representing our firm in next week. Those going should've received special T-shirts for the race. They were distributed yesterday by . . . um . . . my assistant, Marcelle. If you weren't at your desk then, please get one from her later today. Multiple sizes are still available. Also, some of you paid the entry fee in advance. The company will reimburse you for this in cash. Come by my office at your convenience. All right, that's all for now. Thanks.", "ko": "마치기 전에, 다음 주에 여러분 중 몇 분이 우리 회사를 대표하실 자전거 타기 자선 행사에 대해 논의합시다. 가시는 분들은 경기를 위한 특별한 티셔츠를 수령하셨어야 합니다. 그것은 어제… 음… 제 조수인 Marcelle이 나누어 주었습니다. 만약 그때 자리에 계시지 않았다면, 그녀로부터 오늘 늦게 하나를 받아가십시오. 여전히 다양한 사이즈들을 이용하실 수 있습니다. 또한, 여러분 중 일부는 미리 입장료를 지불하셨습니다. 회사가 이것을 여러분에게 현금으로 변제해드릴 것입니다. 편하실 때 제 사무실로 오세요. 좋습니다, 지금은 이게 전부입니다. 감사합니다."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "M-Br", "audio": "Test07_83-85.mp3", "qs": [{"n": 83, "q": "What is the announcement mainly about?", "opts": ["A sports competition", "A celebrity spokesperson", "A business partnership", "A new soft drink"], "ans": 2, "ko": "공지는 주로 무엇에 관한 것인가?"}, {"n": 84, "q": "What did the speaker do this morning?", "opts": ["Formalized a contract", "Met with soccer players", "Visited a sports arena", "Negotiated different rates"], "ans": 0, "ko": "화자는 오늘 아침에 무엇을 했는가?"}, {"n": 85, "q": "What does the speaker say a company will be able to do?", "opts": ["Enter an international market", "Hold a press conference", "Increase its number of online subscribers", "Use a symbol for promotional purposes"], "ans": 3, "ko": "화자는 회사가 무엇을 할 수 있을 것이라고 말하는가?"}], "script": [{"sp": "M", "en": "May I have your attention, everyone? I've got some exciting news to share with you. As of today, our soft drink company will be partnering with the Las Vegas Aces soccer team. In fact, I signed the agreement this morning, making it official. This is a big deal for us. Not only will our drinks be exclusively offered at the Aces' stadium, but we'll also be allowed to use the team logo in our marketing materials. Considering how popular the team is, there's a great chance that this will significantly boost the public's awareness of our brand.", "ko": "모두 주목해 주시겠습니까? 여러분과 공유할 흥미로운 소식이 있습니다. 오늘 날짜로 우리 음료수 회사는 라스베이거스 Aces 축구팀과 제휴할 것입니다. 사실, 저는 오늘 아침에 계약서에 서명을 하여 이것을 공식화했습니다. 이것은 우리에게 중대한 사건입니다. 우리 음료수가 Aces의 경기장에서 독점적으로 제공될 예정일 뿐만 아니라, 또한 우리가 마케팅 자료에 그 팀의 로고를 사용하는 것이 허용될 것입니다. 그 팀이 얼마나 인기가 있는지를 고려할 때, 이것이 우리 브랜드에 대한 대중의 인지도를 상당히 증진시킬 가능성이 큽니다."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "W-Cn", "audio": "Test07_86-88.mp3", "qs": [{"n": 86, "q": "What is the broadcast mainly about?", "opts": ["Upcoming local elections", "A scholarship program", "Library membership benefits", "A community investment"], "ans": 3, "ko": "방송은 주로 무엇에 관한 것인가?"}, {"n": 87, "q": "What does the speaker say about Sherry Keenam?", "opts": ["She filled out an application.", "She accepted a proposal.", "She came up with an idea.", "She is going to retire."], "ans": 1, "ko": "화자는 Sherry Keenam에 관해 무엇을 말하는가?"}, {"n": 88, "q": "How can listeners learn more about a project?", "opts": ["By calling an agency", "By listening to some reports", "By going to a Web site", "By attending some meetings"], "ans": 3, "ko": "청자들은 프로젝트에 대해 어떻게 더 알 수 있는가?"}], "script": [{"sp": "W", "en": "Over the weekend, city officials announced plans to allocate $2 million for building a new public library. The decision came after weeks of debate, during which city council members considered how to use a recent federal grant. Some people were hoping that the funds would be spent on road repairs. However, a majority of residents support Mayor Sherry Keenam's decision to approve the library proposal. As of now, no fixed timeline regarding construction has been established, but work is expected to start as soon as this September. To find out the latest details about this development moving forward, residents are welcome to take part in Town Hall meetings every Tuesday evening.", "ko": "주말 동안, 시 공무원들은 새로운 공립 도서관을 짓는 데 200만 달러를 할당한다는 계획을 발표했습니다. 이 결정은 몇 주간의 토론 끝에 나왔는데, 이 기간 동안 시 의원들은 최근의 연방정부 보조금을 어떻게 사용할지 고민했습니다. 일부 사람들은 이 보조금이 도로 보수에 사용되기를 희망했습니다. 하지만, 대다수의 주민들은 도서관 제의를 승인하는 Sherry Keenam 시장의 결정을 지지합니다. 현재로서는, 공사에 대해 확정된 일정은 수립되지 않았지만, 빠르면 이번 9월에 작업이 시작될 것으로 예상됩니다. 앞으로 진행될 이 개발에 대한 최신 세부 사항들을 확인하시기 위해, 주민들은 매주 화요일 저녁 시청 회의에 자유롭게 참여하실 수 있습니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test07_89-91.mp3", "qs": [{"n": 89, "q": "What problem is mentioned?", "opts": ["Sales for a line have dropped.", "A battery will not charge properly.", "Car models received bad press.", "A recall must be carried out."], "ans": 0, "ko": "어떤 문제가 언급되는가?"}, {"n": 90, "q": "What does the speaker imply when he says, \"The impact is expected to be considerable\"?", "opts": ["A factory will bring in additional workers.", "A business will benefit from a merger.", "A schedule change will go into effect today.", "A production strategy will save money."], "ans": 3, "ko": "화자는 \"그 효과는 상당할 것으로 기대됩니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 91, "q": "What will be sent out next week?", "opts": ["A catalog", "A sales forecast", "A product", "A radio commercial"], "ans": 0, "ko": "다음 주에 무엇이 발송될 것인가?"}], "script": [{"sp": "M", "en": "While we have achieved record sales numbers for many of our products this year, car batteries have been an exception. Until recently, our line of automotive batteries was popular among consumers. However, it is now underperforming as more competitors have entered the market. As a result, management has decided to drop the A34 car battery model to reduce production costs. The impact is expected to be considerable. As for models that will remain in production, we'll be sending out an updated product catalog to retail outlets at the end of next week.", "ko": "비록 우리가 올해 우리의 많은 제품들에 대해 기록적인 판매 수치를 달성했지만, 자동차 배터리는 예외였습니다. 최근까지, 우리의 자동차 배터리 종류는 소비자들 사이에서 인기가 있었습니다. 하지만, 더 많은 경쟁업체들이 시장에 진입함으로써 그것은 현재 실적을 내지 못하고 있습니다. 결과적으로, 경영진은 생산비를 줄이기 위해 A34 자동차 배터리 모델을 중단하기로 결정했습니다. 그 효과는 상당할 것으로 기대됩니다. 계속해서 생산할 모델들에 대해서는, 업데이트된 제품 카탈로그를 다음 주 후반에 소매점으로 발송할 것입니다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test07_92-94.mp3", "qs": [{"n": 92, "q": "What will the speaker discuss first?", "opts": ["Reasons for using training manuals", "Ways for making a workplace pleasant", "Methods for recruiting personnel", "Benefits of working fewer hours"], "ans": 1, "ko": "화자는 먼저 무엇을 논의할 것인가?"}, {"n": 93, "q": "What does the speaker mention about some group exercises?", "opts": ["They are no longer open for registration.", "They will take place in an auditorium.", "They had to be delayed by an hour.", "They are aimed at improving trust."], "ans": 3, "ko": "화자는 집단 활동들에 관해 무엇을 언급하는가?"}, {"n": 94, "q": "What does the speaker ask listeners to do?", "opts": ["Find a free seat", "Introduce themselves", "Refer to a handout", "Break up into pairs"], "ans": 1, "ko": "화자는 청자들에게 무엇을 하라고 요청하는가?"}], "script": [{"sp": "W", "en": "It's my pleasure to welcome you all to this workshop on how to improve interpersonal communication within office settings. Over the course of the morning, we'll be talking about a lot of very useful information. First, I'll explain how to encourage personnel to be more engaged and communicative by creating a welcoming working environment. Then, later this morning, we'll discuss a variety of group exercises that you can have employees do to build trust among team members—something essential to good communication. But before all of that, I'd like everyone to quickly tell the group your name and a few details about where you work. Let's start over here on the left.", "ko": "사무실 환경에서 대인 관계 의사소통을 향상시키는 방법에 대한 이 워크숍에 여러분을 맞이하게 되어 기쁩니다. 오전 동안 우리는 굉장히 유용한 많은 정보에 대해 이야기하게 될 것입니다. 우선, 저는 우호적인 업무 환경을 조성함으로써 직원들이 더욱 몰두하고 소통을 잘 하도록 격려하는 방법에 대해 설명할 것입니다. 그러고 나서, 오늘 늦게 우리는 좋은 의사소통에 필수적인 신뢰를 팀 구성원들 사이에서 구축할 수 있도록, 여러분이 직원들에게 시키실 수 있는 다양한 집단 활동들에 대해 논의할 것입니다. 하지만 이 모든 것 이전에, 저는 여러분이 성함과 일하시는 곳에 대한 몇 가지 정보들을 모두에게 얘기해주셨으면 합니다. 여기 왼쪽에서부터 시작합시다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "W-Br", "audio": "Test07_95-97.mp3", "qs": [{"n": 95, "q": "Look at the graphic. When does the speaker want to schedule a book signing?", "opts": ["On Monday", "On Tuesday", "On Wednesday", "On Thursday"], "ans": 2, "ko": "시각 자료를 보시오. 화자는 사인회 일정을 언제로 잡고 싶어 하는가?"}, {"n": 96, "q": "What is located near the bookstore?", "opts": ["A convention center", "A hotel", "An airport", "A company headquarters"], "ans": 1, "ko": "서점 근처에 무엇이 위치해 있는가?"}, {"n": 97, "q": "What does the speaker offer to do?", "opts": ["Call a bookstore", "Send an itinerary", "Provide accommodation", "Arrange transportation"], "ans": 3, "ko": "화자는 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "W", "en": "Mr. Hakeem, this is your assistant Peggy. I'm calling because the manager of Westwood Books wants to schedule a signing event to coincide with the release of your memoir. I know you're very busy next week, but I think it would be best to schedule the event on the same day as the awards ceremony. The hotel where the ceremony is being held is only a 10-minute drive from the bookstore, so you could easily do both. I can arrange for a taxi to pick you up, so you won't have to worry about driving yourself. If you agree with my suggestions, I'll take care of everything.", "ko": "Mr. Hakeem, 당신의 조수 Peggy예요. Westwood 서점의 관리자가 사인회 일정을 당신의 회고록 발간에 맞춰 잡고 싶어 해서 전화드려요. 당신이 다음 주에 굉장히 바쁘다는 걸 알지만, 그 행사를 시상식과 같은 날로 잡는 것이 가장 좋을 것 같아요. 그 시상식이 열리는 호텔은 서점에서 차로 단 10분 거리라서, 당신이 쉽게 둘 다 하실 수 있을 거예요. 직접 운전하는 걸 걱정하지 않으셔도 되도록 제가 당신을 태우러 갈 택시를 준비해드릴 수 있어요. 저의 제안에 동의하신다면, 제가 모든 걸 처리할게요."}], "gimg": "hk_t7_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "W-Am", "audio": "Test07_98-100.mp3", "qs": [{"n": 98, "q": "What did the listener do last week?", "opts": ["Decorated a lobby", "Attended a meeting", "Purchased some items", "Provided some samples"], "ans": 1, "ko": "청자는 지난주에 무엇을 했는가?"}, {"n": 99, "q": "Why did the speaker contact Marvin Griggs?", "opts": ["To explain a delay", "To ask about a deadline", "To request a change", "To get an opinion"], "ans": 3, "ko": "화자는 왜 Marvin Griggs에게 연락했는가?"}, {"n": 100, "q": "Look at the graphic. Which option does the speaker prefer?", "opts": ["Layout 1", "Layout 2", "Layout 3", "Layout 4"], "ans": 2, "ko": "시각 자료를 보시오. 화자는 어떤 선택권을 선호하는가?"}], "script": [{"sp": "W", "en": "Hello, Ms. Coyle. This is Sandra Brink. I want to let you know that I've come to a decision regarding our lobby arrangement. I like the idea that you shared during our meeting last week about placing a table in the center of the room. Clients will appreciate having a place to set down their belongings as they wait to meet with staff. I also contacted my partner Marvin Griggs to get his input, and we agree that the design with a small chair and two long sofas facing each other is the most ideal one. You have my permission to order the appropriate furniture in the fabric styles we discussed before.", "ko": "안녕하세요, Ms. Coyle. 저는 Sandra Brink입니다. 저희 로비 배치에 대해 제가 결정을 내렸다는 것을 알려드리고 싶습니다. 저는 지난주 우리 회의에서 당신이 이야기했던 방의 중앙에 탁자를 놓는 방안이 마음에 듭니다. 고객들은 직원과 만나기 위해 기다리는 동안에 그들의 소지품을 내려놓을 수 있는 공간을 가지는 것에 대해 환영할 겁니다. 저는 제 동업자인 Marvin Griggs에게도 조언을 받기 위해 연락했는데, 저희는 작은 의자 하나와 서로 마주 보는 두 개의 긴 소파를 사용한 디자인이 가장 이상적이라는 데에 동의합니다. 일전에 우리가 논의했던 천으로 된 스타일의 적절한 가구를 주문하는 것에 대해 승인해드립니다."}], "gimg": "hk_t7_g98.jpg"}]};
